features.snippet:
output reg s,cout;
always @(posedge clk or posedge reset) begin
  if (reset == 1) begin
    s = 0;
    cout = c;
  end else begin
    s = a ^ b ^ c;
    cout = 0;
  end
end

reg c,flag;
always @(posedge clk or posedge reset) begin
  if (reset == 1) begin
    flag = 0;
  end else begin
    if (flag == 0) begin
      c = cin;
      flag = 1;
    end
    cout = 0;
    c = (a & b) | (c & b) | (a & c);
  end
end
